/**
 * @summary List active community captains
 */
export const getListCaptainsUrl = (params?: ListCaptainsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/captains?${stringifiedParams}`
    : `/api/captains`;
};

export const listCaptains = async (
  params?: ListCaptainsParams,
  options?: RequestInit,
): Promise<CaptainListResponse> => {
  return customFetch<CaptainListResponse>(getListCaptainsUrl(params), {
    ...options,
    method: "GET",
  });
};

